mapper.select:
SELECT p.id, p.farmer_id, p.name, p.description, p.price, p.stock, p.category, p.images, p.status, p.created_at, fp.name AS farmer_name FROM products p JOIN farmer_profiles fp ON fp.id = p.farmer_id WHERE p.status = 'active'
AND p.category = #{category}
AND p.farmer_id = #{farmerId}
ORDER BY p.created_at DESC

mapper.update:
UPDATE products
SET stock = stock - #{quantity}
WHERE id = #{id} AND stock >= #{quantity}
